import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/linux-java-version.Bae4eMgj.js";const a=JSON.parse(`{"title":"Installing Java on Linux","description":"A step by step guide on how to install Java on Linux.","frontmatter":{"title":"Installing Java on Linux","description":"A step by step guide on how to install Java on Linux.","authors":["IMB11"],"search":false,"files":[]},"headers":[],"relativePath":"1.21.1/players/installing-java/linux.md","filePath":"versions/1.21.1/players/installing-java/linux.md","lastUpdated":1761424914000}`);var o={name:`1.21.1/players/installing-java/linux.md`};function s(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Installing Java on Linux <a class="header-anchor" href="#h1" aria-label="Permalink to “Installing Java on Linux”">​</a></h1><p>This guide will walk you through installing Java 21 on Linux.</p><h2 id="1-check-if-java-is-already-installed" tabindex="-1">1. Check if Java Is Already Installed <a class="header-anchor" href="#1-check-if-java-is-already-installed" aria-label="Permalink to “1. Check if Java Is Already Installed”">​</a></h2><p>Open a terminal, type <code>java -version</code>, and press <kbd>Enter</kbd>.</p><p><img src="/assets/players/installing-java/linux-java-version.png" alt="Terminal with &quot;java -version&quot; typed in" loading="lazy"></p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>To use Minecraft 1.21, you&#39;ll need at least Java 21 installed. If this command displays any version lower than 21, you&#39;ll need to update your existing Java installation.</p></div><h2 id="2-downloading-and-installing-java" tabindex="-1">2. Downloading and Installing Java 21 <a class="header-anchor" href="#2-downloading-and-installing-java" aria-label="Permalink to “2. Downloading and Installing Java 21”">​</a></h2><p>We recommend using OpenJDK 21, which is available for most Linux distributions.</p><h3 id="arch-linux" tabindex="-1">Arch Linux <a class="header-anchor" href="#arch-linux" aria-label="Permalink to “Arch Linux”">​</a></h3><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>For more information on installing Java on Arch Linux, see the <a href="https://wiki.archlinux.org/title/Java" target="_blank" rel="noreferrer">Arch Linux Wiki</a>.</p></div><p>You can install the latest JRE from the official repositories:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jre-openjdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>If you&#39;re running a server without the need for a graphical UI, you can install the headless version instead:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jre-openjdk-headless</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>If you plan to develop mods, you&#39;ll need the JDK instead:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jdk-openjdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="debian-ubuntu" tabindex="-1">Debian/Ubuntu <a class="header-anchor" href="#debian-ubuntu" aria-label="Permalink to “Debian/Ubuntu”">​</a></h3><p>You can install Java 21 using <code>apt</code> with the following commands:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openjdk-21-jdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="fedora" tabindex="-1">Fedora <a class="header-anchor" href="#fedora" aria-label="Permalink to “Fedora”">​</a></h3><p>You can install Java 21 using <code>dnf</code> with the following commands:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dnf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> java-21-openjdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>If you don&#39;t need a graphical UI, you can install the headless version instead:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dnf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> java-21-openjdk-headless</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>If you plan to develop mods, you&#39;ll need the JDK instead:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dnf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> java-21-openjdk-devel</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="other-linux-distributions" tabindex="-1">Other Linux Distributions <a class="header-anchor" href="#other-linux-distributions" aria-label="Permalink to “Other Linux Distributions”">​</a></h3><p>If your distribution isn&#39;t listed above, you can download the latest JRE from <a href="https://adoptium.net/temurin/" target="_blank" rel="noreferrer">Adoptium</a></p><p>You should refer to an alternative guide for your distribution if you plan to develop mods.</p><h2 id="3-verify-that-java-is-installed" tabindex="-1">3. Verify That Java 21 Is Installed <a class="header-anchor" href="#3-verify-that-java-is-installed" aria-label="Permalink to “3. Verify That Java 21 Is Installed”">​</a></h2><p>Once the installation is complete, you can verify that Java 21 is installed by opening a terminal and typing <code>java -version</code>.</p><p>If the command runs successfully, you will see something like shown before, where the Java version is displayed:</p><p><img src="/assets/players/installing-java/linux-java-version.png" alt="Terminal with &quot;java -version&quot; typed in" loading="lazy"></p>`,33)]])}var c=r(o,[[`render`,s]]);export{a as __pageData,c as default};